delete from dish
where id in

        #{id}

mapper.select:
select d.id, d.name, d.category_id, d.price, d.image, d.description, d.status, d.update_time, c.name as categoryName, df.id as flavor_id, df.name as flavor_name, df.value as flavor_value, df.dish_id from dish d left join category c on d.category_id = c.id left join dish_flavor df on d.id = df.dish_id
and d.category_id = #{categoryId}
and d.status = #{status}
order by d.create_time desc
